+import { $internal } from '../common';
+import { createEntity, destroyEntity } from '../entity/entity';
+import type { Entity } from '../entity/types';
+import { allocateEntity, isEntityAlive, releaseEntity } from '../entity/utils/entity-index';
+import { getRelationTargets, hasRelationPair } from '../relation/relation';
+import type { RelationPair } from '../relation/types';
+import { isRelationPair } from '../relation/utils/is-relation';
+import { addTrait, getTrait, hasTrait, removeTrait } from '../trait/trait';
+import type { ConfigurableTrait, Trait } from '../trait/types';
+import type { DeferredCommand, DeferredScope, DeferredWorld, World } from './types';
+
+function scope(world: World): DeferredScope {
+    const scopes = world[$internal].deferredScopes;
+    return scopes[scopes.length - 1]!;
+}
+
+export function beginDeferredScope(world: World) {
+    world[$internal].deferredScopes.push({ commands: [], spawned: new Set() });
+}
+
+export function endDeferredScope(world: World) {
+    flushDeferred(world);
+    world[$internal].deferredScopes.pop();
+}
+
+export function hasDeferredCommands(world: World, entity?: Entity) {
+    return world[$internal].deferredScopes.some((s) =>
+        entity === undefined ? s.commands.length > 0 : s.commands.some((c) => c.entity === entity)
+    );
+}
+
+/** The projected liveness of an entity. Pending spawns are intentionally invisible to queries. */
+export function isDeferredAlive(world: World, entity: Entity) {
+    let alive = isEntityAlive(world[$internal].entityIndex, entity);
+    for (const s of world[$internal].deferredScopes) {
+        for (const command of s.commands) {
+            if (command.entity !== entity) continue;
+            if (command.type === 'spawn') alive = true;
+            if (command.type === 'destroy') alive = false;
+        }
+    }
+    return alive;
+}
+
+function commandsFor(world: World, entity: Entity) {
+    return world[$internal].deferredScopes.flatMap((s) => s.commands.filter((c) => c.entity === entity));
+}
+
+export function deferredHas(world: World, entity: Entity, trait: Trait | RelationPair) {
+    if (!hasDeferredCommands(world, entity)) return isRelationPair(trait)
+        ? hasRelationPair(world, entity, trait)
+        : hasTrait(world, entity, trait);
+    if (!isDeferredAlive(world, entity)) return false;
+
+    let value = isRelationPair(trait)
+        ? hasRelationPair(world, entity, trait)
+        : hasTrait(world, entity, trait as Trait);
+    for (const command of commandsFor(world, entity)) {
+        const traits = command.type === 'add' || command.type === 'spawn' ? command.traits : command.type === 'remove' ? command.traits : [];
+        if (command.type === 'destroy') return false;
+        for (const item of traits) {
+            if (isRelationPair(trait) && isRelationPair(item)) {
+                const a = trait[$internal], b = item[$internal];
+                if (a.relation === b.relation && (b.target === '*' || a.target === b.target)) value = command.type !== 'remove';
+            } else if (!isRelationPair(trait) && !isRelationPair(item)) {
+                const itemTrait = Array.isArray(item) ? item[0] : item;
+                if (itemTrait === trait) value = command.type !== 'remove';
+            }
+        }
+    }
+    return value;
+}
+
+export function deferredGet(world: World, entity: Entity, trait: Trait | RelationPair) {
+    if (!deferredHas(world, entity, trait)) return undefined;
+    let value = getTrait(world, entity, trait);
+    for (const command of commandsFor(world, entity)) {
+        if (command.type !== 'add' && command.type !== 'spawn') continue;
+        for (const item of command.traits) {
+            if (isRelationPair(trait) && isRelationPair(item)) {
+                const a = trait[$internal], b = item[$internal];
+                if (a.relation === b.relation && a.target === b.target) value = b.params;
+            } else if (!isRelationPair(trait) && !isRelationPair(item)) {
+                const itemTrait = Array.isArray(item) ? item[0] : item;
+                if (itemTrait === trait && Array.isArray(item)) value = item[1];
+            }
+        }
+    }
+    return value;
+}
+
+function queue(world: World, command: DeferredCommand) {
+    const current = scope(world);
+    // A spawn immediately followed by destroy has no observable existence.
+    if (command.type === 'destroy' && current.spawned.has(command.entity)) {
+        current.commands = current.commands.filter((c) => c.entity !== command.entity);
+        current.spawned.delete(command.entity);
+        releaseEntity(world[$internal].entityIndex, command.entity);
+        return;
+    }
+    // Repeated adds to a pending trait/pair are a single add with the newest value.
+    if (command.type === 'add') {
+        for (const trait of command.traits) {
+            const found = current.commands.findLast((c) => c.type === 'add' && c.entity === command.entity && c.traits.some((old) => sameConfig(old, trait)));
+            if (found && found.type === 'add') found.traits = found.traits.map((old) => sameConfig(old, trait) ? trait : old);
+            else current.commands.push({ type: 'add', entity: command.entity, traits: [trait] });
+        }
+        return;
+    }
+    current.commands.push(command);
+}
+
+function sameConfig(a: ConfigurableTrait, b: ConfigurableTrait) {
+    if (isRelationPair(a) && isRelationPair(b)) return a[$internal].relation === b[$internal].relation && a[$internal].target === b[$internal].target;
+    if (isRelationPair(a) || isRelationPair(b)) return false;
+    return (Array.isArray(a) ? a[0] : a) === (Array.isArray(b) ? b[0] : b);
+}
+
+export function createDeferred(world: World): DeferredWorld {
+    return {
+        spawn(...traits) {
+            // Reserve an entity now so it can be used as a relation target in this scope.
+            const entity = allocateEntity(world[$internal].entityIndex);
+            const current = scope(world);
+            current.spawned.add(entity);
+            queue(world, { type: 'spawn', entity, traits });
+            return entity;
+        },
+        destroy(entity) { queue(world, { type: 'destroy', entity }); },
+        add(entity, ...traits) { queue(world, { type: 'add', entity, traits }); },
+        remove(entity, ...traits) { queue(world, { type: 'remove', entity, traits }); },
+        addExclusive(entity, ...pairs) {
+            for (const pair of pairs) {
+                const { relation, target } = pair[$internal];
+                queue(world, { type: 'remove', entity, traits: [relation('*')] });
+                if (target !== '*') queue(world, { type: 'add', entity, traits: [pair] });
+            }
+        },
+        flush() { flushDeferred(world); },
+    };
+}
+
+export function flushDeferred(world: World) {
+    const current = scope(world);
+    if (!current?.commands.length) return;
+    const commands = current.commands;
+    current.commands = [];
+    current.spawned.clear();
+    for (const command of commands) {
+        // Spawned entities were allocated as reservations; initialize them only here.
+        if (command.type === 'spawn') {
+            if (!isEntityAlive(world[$internal].entityIndex, command.entity)) continue;
+            world[$internal].entityTraits.set(command.entity, new Set());
+            addTrait(world, command.entity, ...command.traits);
+        } else if (!isEntityAlive(world[$internal].entityIndex, command.entity)) {
+            continue;
+        } else if (command.type === 'destroy') {
+            if (command.entity === world[$internal].worldEntity) throw new Error('Koota: The world entity cannot be destroyed by a deferred command.');
+            destroyEntity(world, command.entity);
+        } else if (command.type === 'add') {
+            addTrait(world, command.entity, ...command.traits);
+        } else {
+            removeTrait(world, command.entity, ...command.traits);
+        }
+    }
+}
